INSERT INTO news (title, short_description, content, created_at) VALUES
('Відкриття нового культурного центру у Вінниці', 'У місті відкрили сучасний культурний центр із виставковими залами, коворкінгом та майданчиком для заходів.', 'У Вінниці відбулося урочисте відкриття нового культурного центру "Простір". Заклад розташований у реконструйованій будівлі заводу в центрі міста. На трьох поверхах розмістились виставкові зали, коворкінг-зона, конференц-зал на 200 місць та відкрита тераса. Центр вже анонсував перші заходи — виставку сучасного українського мистецтва та серію публічних лекцій.', '2026-04-28 09:15:00'),
('Україна підписала угоду про партнерство з ЄС у сфері цифрових технологій', 'Документ передбачає спільні інвестиції в розвиток цифрової інфраструктури та підготовку IT-фахівців.', 'Міністерство цифрової трансформації України підписало угоду про стратегічне партнерство з Єврокомісією. Документ охоплює три напрями: розвиток хмарної інфраструктури державних органів, програми перекваліфікації фахівців та спільні пілотні проєкти у сфері штучного інтелекту. Фінансування угоди складе 120 млн євро впродовж трьох років.', '2026-04-25 14:30:00'),
('Стартував прийом заявок на грант для малого бізнесу', 'Програма підтримки підприємців передбачає гранти до 500 тисяч гривень на розвиток виробництва.', 'Міністерство економіки розпочало прийом заявок на отримання грантів для малого та середнього бізнесу в межах програми "Зроблено в Україні". Максимальний розмір гранту — 500 000 гривень. Пріоритет надається виробничим підприємствам, які експортують продукцію або мають потенціал для виходу на зовнішні ринки. Заявки приймаються до 30 травня 2025 року.', '2026-04-22 11:00:00'),
('Нові маршрути громадського транспорту запрацювали у Львові', 'Місто запустило чотири нові автобусні маршрути, які з\'єднають спальні райони з центром.', 'Львівська міська рада затвердила та запустила чотири нові автобусні маршрути. Вони охоплюють мікрорайони Сихів, Рясне-2, Левандівку та Збоїща. Автобуси курсують кожні 15 хвилин у години пік і кожні 25 хвилин у решту часу. Всі нові маршрути обладнані низькопідлоговим рухомим складом.', '2026-04-19 08:45:00'),
('Українські стартапи залучили рекордний обсяг інвестицій у першому кварталі', 'За даними аналітиків, загальний обсяг інвестицій у вітчизняні технологічні компанії перевищив 80 млн доларів.', 'За підсумками першого кварталу 2025 року українські технологічні стартапи залучили понад 80 млн доларів інвестицій — це на 35% більше, ніж за аналогічний період минулого року. Найбільші раунди закрили компанії у сферах фінтех, агротех та кібербезпеки. Лідером за кількістю угод залишається київська екосистема, проте все більше проєктів реєструється у Варшаві та Берліні.', '2026-04-15 16:20:00'),
('У школах запровадять новий предмет з медіаграмотності', 'Міністерство освіти анонсувало введення обов\'язкового курсу для учнів 8–9 класів із вересня 2025 року.', 'Міністерство освіти і науки України оголосило про введення нового обов\'язкового предмету "Медіаграмотність та критичне мислення" для учнів 8–9 класів. Курс розрахований на 35 годин на рік і охоплює теми: розпізнавання дезінформації, робота з джерелами, цифрова гігієна та основи журналістики. Пілотне впровадження відбудеться у 200 школах із вересня 2025 року.', '2026-04-12 10:00:00'),
('Відновлено залізничне сполучення між трьома обласними центрами', 'Укрзалізниця відновила пасажирські рейси на маршрутах, що були призупинені у 2022 році.', 'Укрзалізниця оголосила про відновлення пасажирського сполучення між Полтавою, Кременчуком та Кропивницьким. Поїзди курсуватимуть двічі на день — вранці та ввечері. Час у дорозі між крайніми точками маршруту складає 3 години 20 хвилин. Квитки вже доступні для купівлі на сайті та в мобільному додатку.', '2026-04-09 13:10:00'),
('Нова програма озеленення міст охопить 25 регіонів', 'До кінця 2025 року в українських містах планується висадити понад мільйон дерев у рамках екологічної ініціативи.', 'Кабінет Міністрів затвердив програму масштабного озеленення міських територій "Зелена Україна 2025". Впродовж поточного року в 25 регіонах країни буде висаджено понад 1 млн дерев та кущів. Акцент зроблено на посухостійких та місцевих видах рослин. Програма фінансується з держбюджету та за рахунок міжнародних екологічних фондів.', '2026-04-05 09:30:00'),
('Відкрито реєстрацію на безкоштовні IT-курси для ветеранів', 'Державна програма перекваліфікації пропонує 500 місць на курсах із веб-розробки, тестування та кібербезпеки.', 'Міністерство у справах ветеранів спільно з провідними IT-компаніями оголосило реєстрацію на безкоштовні курси перекваліфікації. Програма розрахована на 6 місяців і включає онлайн-навчання, менторську підтримку та допомогу з працевлаштуванням. Доступні напрями: веб-розробка (JavaScript, PHP), QA-тестування та основи кібербезпеки. Реєстрація відкрита до 15 травня.', '2026-04-02 15:00:00'),
('Запущено онлайн-платформу для моніторингу якості повітря', 'Новий сервіс в реальному часі показує рівень забруднення в 50 містах України на основі даних із сенсорних мереж.', 'Міністерство захисту довкілля презентувало онлайн-платформу EcoAir.ua для моніторингу якості повітря. Сервіс агрегує дані з 500 сенсорів у 50 містах і відображає показники PM2.5, PM10, CO₂ та NO₂ в режимі реального часу. На платформі доступні історичні дані за останні два роки та функція сповіщень при перевищенні норм. Мобільний додаток вийде у травні.', '2026-03-28 11:45:00');
